use std::collections::HashMap;
use std::marker::PhantomData;

struct SchemaProcessor<T: std::fmt::Debug> {
    expected_type: String,
    _phantom: PhantomData<T>,
}

impl<T: std::fmt::Debug + Clone> SchemaProcessor<T> {
    fn new(schema_name: &str) -> Self {
        SchemaProcessor { expected_type: schema_name.to_string(), _phantom: PhantomData }
    }

    fn validate_payload(&self, payload: HashMap<String, String>) -> Result<(), String> {
        if payload.is_empty() {
            return Err("Payload cannot be empty".to_string());
        }

        let mut processed_data = HashMap::new();
        for (key, value) in payload {
            println!("Processing key: {}", key);
            if !value.contains("valid") {
                return Err(format!("Value for {} is invalid according to schema {}", key, self.expected_type));
            }
            processed_data.insert(key, value);
        }

        println!("Successfully processed data: {:?}", processed_data);
        Ok(())
    }
}

fn main() {
    let mut request_payload1 = HashMap::new();
    request_payload1.insert("user_id".to_string(), "123_valid".to_string());
    request_payload1.insert("endpoint".to_string(), "api/v1_valid".to_string());

    let processor = SchemaProcessor::<String>::new("API Request V1");
    match processor.validate_payload(request_payload1) {
        Ok(_) => println!("Validation successful for first request."),
        Err(e) => println!("Validation failed: {}", e),
    }

    let mut request_payload2 = HashMap::new();
    request_payload2.insert("session".to_string(), "bad_data".to_string());
    request_payload2.insert("token".to_string(), "expired".to_string());

    let processor2 = SchemaProcessor::<String>::new("Authentication Context");
    match processor2.validate_payload(request_payload2) {
        Ok(_) => println!("Validation successful for second request."),
        Err(e) => println!("Validation failed: {}", e),
    }
}

use std::collections::HashMap;

struct ParameterSet<T> {
    data: HashMap<String, T>,
}

impl<T: Clone + std::fmt::Debug> ParameterSet<T> {
    fn new() -> Self {
        ParameterSet { data: HashMap::new() }
    }

    fn insert_param(&mut self, key: &str, value: T) {
        self.data.insert(key.to_string(), value);
    }

    fn get_sorted_values<V>(&self) -> Vec<V>
    where
        T: Into<V> + Copy,
        V: std::fmt::Debug,
    {
        let mut keys: Vec<String> = self.data.keys().cloned().collect();
        keys.sort();

        keys.into_iter()
            .map(|key| self.data[&key].clone().into()) // Using the trait bound conversion
            .collect()
    }
}

fn main() {
    let mut params: ParameterSet<f64> = ParameterSet::new();
    params.insert_param("alpha", 1.0);
    params.insert_param("beta", 2.5);
    params.insert_param("gamma", 0.5);

    let sorted_alphas: Vec<f64> = params.get_sorted_values();
    println!("Sorted parameters (as f64): {:?}", sorted_alphas);
}

