use std::error::Error;
use std::fmt;

trait RunnableAlgorithm<T> {
    fn execute(&self, data: T) -> Result<String, Box<dyn Error>>;
}

struct DatabaseWorker { id: u32 }

impl<T: Send + 'static> RunnableAlgorithm<T> for DatabaseWorker {
    fn execute(&self, _data: T) -> Result<String, Box<dyn Error>> {
        Ok(format!("Database worker {} successfully processed the request.", self.id))
    }
}

struct NetworkWorker { endpoint: String }

impl<T> RunnableAlgorithm<T> for NetworkWorker {
    fn execute(&self, _data: T) -> Result<String, Box<dyn Error>> {
        Ok(format!("Network worker {} pinged successfully.", self.endpoint))
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let db_worker = DatabaseWorker { id: 42 };
    let net_worker = NetworkWorker { endpoint: "api.example.com".to_string() };

    type GenericRunner = Box<dyn RunnableAlgorithm<i32> + Send>;

    let db_runner: GenericRunner = Box::new(db_worker);
    let net_runner: GenericRunner = Box::new(net_worker);

    println!("n--- Running Database Task ---n");
    match db_runner.execute(10) {
        Ok(msg) => println!("Success: {}", msg),
        Err(e) => eprintln!("Failure: {}", e),
    }

    println!("n--- Running Network Task ---n");
    match net_runner.execute(20) {
        Ok(msg) => println!("Success: {}", msg),
        Err(e) => eprintln!("Failure: {}", e),
    }

    Ok(())
}

use std::ops::{Add, Mul};
use std::fmt::Debug;

trait Numeric<T> {
    fn from_iter(data: impl Iterator<Item = T>) -> Vec<T>;
}

impl<T> Numeric<T> for T
where
    T: Copy + Default + Add<Output = T> + Debug,
{
    fn from_iter(data: impl Iterator<Item = T>) -> Vec<T> {
        data.collect()
    }
}

struct Matrix<T> {
    rows: usize,
    cols: usize,
    data: Vec<T>,
}

impl<T: Copy + Default + Add<Output = T> + Debug> Matrix<T> {
    fn new(rows: usize, cols: usize) -> Self {
        Matrix { rows, cols, data: vec![T::default(); rows * cols] }
    }

    fn get(&self, row: usize, col: usize) -> T {
        self.data[row * self.cols + col]
    }

    fn set(&mut self, row: usize, col: usize, val: T) {
        self.data[row * self.cols + col] = val;
    }
}

trait CovarianceCalculator<T> {
    fn calculate_covariance(m1: &Matrix<T>, m2: &Matrix<T>) -> Matrix<T>;
}

impl<T> CovarianceCalculator<T> for T
where
    T: Copy + Default + Add<Output = T> + Mul<Output = T> + Debug + 'static,
{
    fn calculate_covariance(m1: &Matrix<T>, m2: &Matrix<T>) -> Matrix<T> {
        let num_samples = m1.rows;
        if num_samples == 0 || m1.cols != m2.cols {
            return Matrix::new(0, 0);
        }

        let mut result = Matrix::new(m1.cols, m2.cols);

        for i in 0..m1.cols {
            for j in 0..m2.cols {
                let mut sum_prod: T = T::default();
                for k in 0..num_samples {
                    let val1 = m1.get(k, i);
                    let val2 = m2.get(k, j);
                    sum_prod = sum_prod + (val1 * val2);
                }
                result.set(i, j, sum_prod); 
            }
        }
        result
    }
}

fn main() {
    let mut float_matrix1: Matrix<f64> = Matrix::new(3, 2);
    let mut float_matrix2: Matrix<f64> = Matrix::new(3, 2);

    float_matrix1.set(0, 0, 1.0);
    float_matrix1.set(1, 0, 2.0);
    float_matrix1.set(2, 0, 3.0);
    float_matrix1.set(0, 1, 4.0);
    float_matrix1.set(1, 1, 5.0);
    float_matrix1.set(2, 1, 6.0);

    float_matrix2.set(0, 0, 7.0);
    float_matrix2.set(1, 0, 8.0);
    float_matrix2.set(2, 0, 9.0);
    float_matrix2.set(0, 1, 10.0);
    float_matrix2.set(1, 1, 11.0);
    float_matrix2.set(2, 1, 12.0);

    let _cov = f64::calculate_covariance(&float_matrix1, &float_matrix2);
}
